import SwiftUI
import Combine

// MARK: - Models

struct Stock: Identifiable, Hashable {
    let id = UUID()
    let symbol: String
    let name: String
    var currentPrice: Double
    var priceChange: Double
    var priceChangePercentage: Double {
        guard currentPrice - priceChange != 0 else { return 0 }
        return (priceChange / (currentPrice - priceChange)) * 100
    }
}

struct PortfolioItem: Identifiable, Hashable {
    let id = UUID()
    let stock: Stock
    var quantity: Int
    var averageCost: Double

    var currentValue: Double {
        stock.currentPrice * Double(quantity)
    }

    var totalCost: Double {
        averageCost * Double(quantity)
    }

    var profitLoss: Double {
        currentValue - totalCost
    }

    var profitLossPercentage: Double {
        guard totalCost != 0 else { return 0 }
        return (profitLoss / totalCost) * 100
    }
}

struct Trade: Identifiable {
    let id = UUID()
    let stockSymbol: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let date: Date
}

enum TradeType: String, CaseIterable, Identifiable {
    case buy = "Buy"
    case sell = "Sell"
    var id: String { self.rawValue }
}

// MARK: - Services

class TradingService: ObservableObject {
    @Published var availableStocks: [Stock] = []
    @Published var userPortfolio: [PortfolioItem] = []
    @Published var accountBalance: Double = 100000.00
    @Published var tradeHistory: [Trade] = []

    private var cancellables = Set<AnyCancellable>()
    private let priceUpdateInterval: TimeInterval = 2.0 // Simulate real-time updates every 2 seconds

    init() {
        // Initialize with some mock stocks
        availableStocks = [
            Stock(symbol: "AAPL", name: "Apple Inc.", currentPrice: 170.00, priceChange: 0.0),
            Stock(symbol: "MSFT", name: "Microsoft Corp.", currentPrice: 420.00, priceChange: 0.0),
            Stock(symbol: "GOOGL", name: "Alphabet Inc.", currentPrice: 155.00, priceChange: 0.0),
            Stock(symbol: "AMZN", name: "Amazon.com Inc.", currentPrice: 185.00, priceChange: 0.0),
            Stock(symbol: "TSLA", name: "Tesla Inc.", currentPrice: 180.00, priceChange: 0.0),
            Stock(symbol: "NVDA", name: "NVIDIA Corp.", currentPrice: 900.00, priceChange: 0.0),
            Stock(symbol: "META", name: "Meta Platforms Inc.", currentPrice: 490.00, priceChange: 0.0)
        ]

        // Start simulating real-time price updates
        Timer.publish(every: priceUpdateInterval, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.updateStockPrices()
            }
            .store(in: &cancellables)
    }

    private func updateStockPrices() {
        for i in 0..<availableStocks.count {
            let originalPrice = availableStocks[i].currentPrice
            let changeFactor = Double.random(in: -0.01...0.01) // +/- 1% change
            let newPrice = originalPrice * (1 + changeFactor)
            let priceChange = newPrice - originalPrice
            availableStocks[i].currentPrice = max(0.01, newPrice) // Ensure price doesn't go below 0
            availableStocks[i].priceChange = priceChange
        }
    }

    func executeTrade(stock: Stock, type: TradeType, quantity: Int) -> Bool {
        guard quantity > 0 else { return false }
        let tradeCost = Double(quantity) * stock.currentPrice

        switch type {
        case .buy:
            guard accountBalance >= tradeCost else {
                print("Insufficient balance for buy order.")
                return false
            }

            accountBalance -= tradeCost
            if let index = userPortfolio.firstIndex(where: { $0.stock.symbol == stock.symbol }) {
                // Update existing holding
                let existingItem = userPortfolio[index]
                let newTotalCost = existingItem.totalCost + tradeCost
                let newTotalQuantity = existingItem.quantity + quantity
                userPortfolio[index].quantity = newTotalQuantity
                userPortfolio[index].averageCost = newTotalCost / Double(newTotalQuantity)
            } else {
                // Add new holding
                userPortfolio.append(PortfolioItem(stock: stock, quantity: quantity, averageCost: stock.currentPrice))
            }
            tradeHistory.append(Trade(stockSymbol: stock.symbol, type: .buy, quantity: quantity, price: stock.currentPrice, date: Date()))
            return true

        case .sell:
            guard let index = userPortfolio.firstIndex(where: { $0.stock.symbol == stock.symbol }) else {
                print("Stock not found in portfolio for sell order.")
                return false
            }
            let holding = userPortfolio[index]
            guard holding.quantity >= quantity else {
                print("Insufficient quantity to sell.")
                return false
            }

            accountBalance += tradeCost
            if holding.quantity == quantity {
                userPortfolio.remove(at: index)
            } else {
                userPortfolio[index].quantity -= quantity
            }
            tradeHistory.append(Trade(stockSymbol: stock.symbol, type: .sell, quantity: quantity, price: stock.currentPrice, date: Date()))
            return true
        }
    }
}

// MARK: - View Models

class MarketViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    private var cancellables = Set<AnyCancellable>()

    init(tradingService: TradingService) {
        tradingService.$availableStocks
            .assign(to: \.stocks, on: self)
            .store(in: &cancellables)
    }
}

class TradeViewModel: ObservableObject {
    @Published var selectedStock: Stock?
    @Published var tradeType: TradeType = .buy
    @Published var quantity: String = "1"
    @Published var showAlert: Bool = false
    @Published var alertMessage: String = ""

    private let tradingService: TradingService

    init(tradingService: TradingService) {
        self.tradingService = tradingService
    }

    var transactionAmount: Double {
        guard let stock = selectedStock, let qty = Int(quantity), qty > 0 else { return 0 }
        return Double(qty) * stock.currentPrice
    }

    var canExecuteTrade: Bool {
        guard let stock = selectedStock, let qty = Int(quantity), qty > 0 else { return false }
        if tradeType == .buy {
            return tradingService.accountBalance >= Double(qty) * stock.currentPrice
        } else { // Sell
            if let holding = tradingService.userPortfolio.first(where: { $0.stock.symbol == stock.symbol }) {
                return holding.quantity >= qty
            }
            return false
        }
    }

    func executeTrade() {
        guard let stock = selectedStock, let qty = Int(quantity), qty > 0 else {
            alertMessage = "Please enter a valid quantity."
            showAlert = true
            return
        }

        if tradingService.executeTrade(stock: stock, type: tradeType, quantity: qty) {
            alertMessage = "\(tradeType.rawValue) order for \(qty) shares of \(stock.symbol) executed successfully!"
            quantity = "1" // Reset quantity after successful trade
        } else {
            alertMessage = "Trade failed. \(tradeType == .buy ? "Insufficient funds." : "Insufficient shares.")"
        }
        showAlert = true
    }
}

class PortfolioViewModel: ObservableObject {
    @Published var portfolioItems: [PortfolioItem] = []
    @Published var tradeHistory: [Trade] = []
    private var cancellables = Set<AnyCancellable>()

    init(tradingService: TradingService) {
        tradingService.$userPortfolio
            .assign(to: \.portfolioItems, on: self)
            .store(in: &cancellables)
        
        tradingService.$tradeHistory
            .assign(to: \.tradeHistory, on: self)
            .store(in: &cancellables)
    }

    var totalPortfolioValue: Double {
        portfolioItems.reduce(0) { $0 + $1.currentValue }
    }

    var totalPortfolioProfitLoss: Double {
        portfolioItems.reduce(0) { $0 + $1.profitLoss }
    }
}

class AccountViewModel: ObservableObject {
    @Published var accountBalance: Double = 0.0
    @Published var totalPortfolioValue: Double = 0.0
    @Published var netWorth: Double = 0.0

    private var cancellables = Set<AnyCancellable>()

    init(tradingService: TradingService) {
        tradingService.$accountBalance
            .assign(to: \.accountBalance, on: self)
            .store(in: &cancellables)

        tradingService.$userPortfolio
            .map { items in
                items.reduce(0) { $0 + ($1.stock.currentPrice * Double($1.quantity)) }
            }
            .assign(to: \.totalPortfolioValue, on: self)
            .store(in: &cancellables)

        Publishers.CombineLatest(tradingService.$accountBalance, tradingService.$userPortfolio)
            .map { balance, items in
                balance + items.reduce(0) { $0 + ($1.stock.currentPrice * Double($1.quantity)) }
            }
            .assign(to: \.netWorth, on: self)
            .store(in: &cancellables)
    }
}

