                            Spacer()
                            Text(stock.currentPrice, format: .currency(code: "USD"))
                                .font(.subheadline)
                        }
                    }
                } else {
                    Text("Select a stock from the Market tab to trade.")
                        .foregroundColor(.gray)
                }

                Section(header: Text("Trade Details")) {
                    Picker("Type", selection: $viewModel.tradeType) {
                        ForEach(TradeType.allCases) { type in
                            Text(type.rawValue).tag(type)
                        }
                    }
                    .pickerStyle(.segmented)

                    TextField("Quantity", text: $viewModel.quantity)
                        .keyboardType(.numberPad)
                        .onChange(of: viewModel.quantity) { newValue in
                            viewModel.quantity = newValue.filter { $0.isNumber }
                        }

                    HStack {
                        Text("Estimated Cost/Proceeds:")
                        Spacer()
                        Text(viewModel.transactionAmount, format: .currency(code: "USD"))
                            .fontWeight(.semibold)
                    }
                }

                Section {
                    Button(action: viewModel.executeTrade) {
                        Text("\(viewModel.tradeType.rawValue) Shares")
                            .font(.headline)
                            .frame(maxWidth: .infinity)
                    }
                    .tint(.blue)
                    .buttonStyle(.borderedProminent)
                    .disabled(!viewModel.canExecuteTrade || viewModel.selectedStock == nil)
